# --- Vector Database ---
class VectorDatabase:
    """Simple file-based vector database using cosine similarity."""

    def __init__(self, db_path: str = VECTOR_DB_PATH):
        self.db_path = db_path
        self.documents: list[dict] = []
        self.embeddings: list[list[float]] = []
        self._load()

    def _load(self):
        if os.path.exists(self.db_path):
            with open(self.db_path, "r", encoding="utf-8") as f:
                data = json.load(f)
                self.documents = data.get("documents", [])
                self.embeddings = data.get("embeddings", [])
            print(f"Loaded {len(self.documents)} document chunks from vector store.")
        else:
            self.documents = []
            self.embeddings = []

    def _save(self):
        data = {
            "documents": self.documents,
            "embeddings": self.embeddings,
        }
        with open(self.db_path, "w", encoding="utf-8") as f:
            json.dump(data, f)
        print(f"Saved {len(self.documents)} document chunks to vector store.")

    def add_document(self, text: str, metadata: dict, embedding: list[float]):
        content_hash = hashlib.md5(text.encode()).hexdigest()
        for doc in self.documents:
            if doc.get("content_hash") == content_hash:
                return  # Skip duplicate

        self.documents.append({
            "text": text,
            "metadata": metadata,
            "content_hash": content_hash,
        })
        self.embeddings.append(embedding)

    def search(self, query_embedding: list[float], top_k: int = TOP_K) -> list[dict]:
        if not self.embeddings:
            return []

        query_vec = np.array(query_embedding)
        scores = []
        for i, emb in enumerate(self.embeddings):
            doc_vec = np.array(emb)
            # Cosine similarity
            similarity = np.dot(query_vec, doc_vec) / (
                np.linalg.norm(query_vec) * np.linalg.norm(doc_vec) + 1e-10
            )
            scores.append((i, similarity))

        scores.sort(key=lambda x: x[1], reverse=True)
        results = []
        for idx, score in scores[:top_k]:
            result = {
                **self.documents[idx],
                "similarity_score": float(score),
            }
            results.append(result)
        return results

    def clear(self):
        self.documents = []
        self.embeddings = []
        self._save()

    @property
    def size(self) -> int:
        return len(self.documents)


# --- Document Processing ---
class DocumentProcessor:
    """Handles loading and chunking of company documents."""

    SUPPORTED_EXTENSIONS = {".txt", ".md", ".csv", ".json", ".py", ".html", ".log"}

    @staticmethod
    def load_file(file_path: str) -> Optional[str]:
        path = Path(file_path)
        if path.suffix.lower() not in DocumentProcessor.SUPPORTED_EXTENSIONS:
            print(f"Skipping unsupported file type: {path.name}")
            return None
        try:
            with open(path, "r", encoding="utf-8", errors="ignore") as f:
                return f.read()
        except Exception as e:
            print(f"Error reading {path.name}: {e}")
            return None

    @staticmethod
    def chunk_text(
        text: str, chunk_size: int = CHUNK_SIZE, overlap: int = CHUNK_OVERLAP
    ) -> list[str]:
        """Split text into overlapping chunks by sentences/paragraphs."""
        if not text.strip():
            return []

        # Split by paragraphs first, then by sentences if needed
        paragraphs = text.split("\n\n")
        chunks = []
        current_chunk = ""

        for paragraph in paragraphs:
            paragraph = paragraph.strip()
            if not paragraph:
                continue

            if len(current_chunk) + len(paragraph) <= chunk_size:
                current_chunk += ("\n\n" if current_chunk else "") + paragraph
            else:
                if current_chunk:
                    chunks.append(current_chunk.strip())
                # If a single paragraph is too long, split by sentences
                if len(paragraph) > chunk_size:
                    sentences = paragraph.replace(". ", ".\n").split("\n")
                    sub_chunk = ""
                    for sentence in sentences:
                        sentence = sentence.strip()
                        if not sentence:
                            continue
                        if len(sub_chunk) + len(sentence) <= chunk_size:
                            sub_chunk += (" " if sub_chunk else "") + sentence
                        else:
                            if sub_chunk:
                                chunks.append(sub_chunk.strip())
                            sub_chunk = sentence
                    current_chunk = sub_chunk
                else:
                    current_chunk = paragraph

        if current_chunk.strip():
            chunks.append(current_chunk.strip())

        # Add overlap between chunks
        if overlap > 0 and len(chunks) > 1:
            overlapped_chunks = [chunks[0]]
            for i in range(1, len(chunks)):
                prev_text = chunks[i - 1]
                overlap_text = prev_text[-overlap:] if len(prev_text) > overlap else prev_text
                # Find a clean break point in the overlap
                space_idx = overlap_text.find(" ")
                if space_idx != -1:
                    overlap_text = overlap_text[space_idx + 1:]
                overlapped_chunks.append(overlap_text + " " + chunks[i])
            chunks = overlapped_chunks

        return chunks

    @staticmethod
    def load_directory(directory: str) -> list[dict]:
        """Load all supported documents from a directory."""
        documents = []
        dir_path = Path(directory)
        if not dir_path.exists():
            print(f"Directory not found: {directory}")
            return documents

        for file_path in sorted(dir_path.rglob("*")):
            if file_path.is_file():
                content = DocumentProcessor.load_file(str(file_path))
                if content:
                    chunks = DocumentProcessor.chunk_text(content)
                    for i, chunk in enumerate(chunks):
                        documents.append({
                            "text": chunk,
                            "metadata": {
                                "source": str(file_path),
                                "filename": file_path.name,
                                "chunk_index": i,
                                "total_chunks": len(chunks),
                            },
                        })
        print(f"Loaded {len(documents)} chunks from {directory}")
        return documents


# --- Embedding Service ---
class EmbeddingService:
    """Handles text embedding using OpenAI API."""

    @staticmethod
    def get_embedding(text: str) -> list[float]:
        text = text.replace("\n", " ").strip()
        response = client.embeddings.create(
            input=text,
            model=EMBEDDING_MODEL,
        )
        return response.data[0].embedding

    @staticmethod
    def get_embeddings_batch(texts: list[str], batch_size: int = 100) -> list[list[float]]:
        all_embeddings = []
        for i in range(0, len(texts), batch_size):
            batch = [t.replace("\n", " ").strip() for t in texts[i: i + batch_size]]
            response = client.embeddings.create(
                input=batch,
                model=EMBEDDING_MODEL,
            )
            batch_embeddings = [item.embedding for item in response.data]
            all_embeddings.extend(batch_embeddings)
            print(f"  Embedded {min(i + batch_size, len(texts))}/{len(texts)} chunks...")
        return all_embeddings


# --- RAG System ---
class RAGSystem:
    """Main RAG system that ties everything together."""

    SYSTEM_PROMPT = """You are an internal knowledge base assistant for our company. 
Your job is to answer employee questions based on the provided context from our company documents.

Rules:
1. Only answer based on the provided context. If the context doesn't contain enough information, say so clearly.
2. Be precise and helpful. Quote or reference specific documents when possible.
3. If multiple documents provide relevant information, synthesize them into a coherent answer.
4. Always mention which source document(s) your answer is based on.
5. If the question is ambiguous, ask for clarification.
6. Do not make up information that isn't in the provided context."""

    def __init__(self):
        self.vector_db = VectorDatabase()
        self.embedding_service = EmbeddingService()
        self.doc_processor = DocumentProcessor()
        self.conversation_history: list[dict] = []

    def ingest_documents(self, directory: str = DOCUMENTS_DIR):
        """Load and index all documents from a directory."""
        print(f"\n📂 Ingesting documents from: {directory}")
        documents = self.doc_processor.load_directory(directory)

        if not documents:
            print("No documents found to ingest.")
            return

        texts = [doc["text"] for doc in documents]
        print(f"🔄 Generating embeddings for {len(texts)} chunks...")
        embeddings = self.embedding_service.get_embeddings_batch(texts)

        for doc, embedding in zip(documents, embeddings):
            self.vector_db.add_document(
                text=doc["text"],
                metadata=doc["metadata"],
                embedding=embedding,
            )

        self.vector_db._save()
        print(f"✅ Ingestion complete. Vector store contains {self.vector_db.size} chunks.")

    def ingest_text(self, text: str, source_name: str = "manual_input"):
        """Ingest a single text document."""
        chunks = self.doc_processor.chunk_text(text)
        texts = [chunk for chunk in chunks]
        embeddings = self.embedding_service.get_embeddings_batch(texts)

        for i, (chunk, embedding) in enumerate(zip(chunks, embeddings)):
            self.vector_db.add_document(
                text=chunk,
                metadata={
                    "source": source_name,
                    "filename": source_name,
                    "chunk_index": i,
                    "total_chunks": len(chunks),
                },
                embedding=embedding,
            )
        self.vector_db._save()
        print(f"✅ Ingested '{source_name}' ({len(chunks)} chunks).")

    def retrieve(self, query: str, top_k: int = TOP_K) -> list[dict]:
        """Retrieve relevant document chunks for a query."""
        query_embedding = self.embedding_service.get_embedding(query)
        results = self.vector_db.search(query_embedding, top_k=top_k)
        return results

    def build_prompt(self, query: str, retrieved_docs: list[dict]) -> list[dict]:
        """Build the prompt with retrieved context."""
        context_parts = []
        for i, doc in enumerate(retrieved_docs, 1):
            source = doc["metadata"].get("filename", "Unknown")
            score = doc.get("similarity_score", 0)
            context_parts.append(
                f"--- Document {i} (Source: {source}, Relevance: {score:.3f}) ---\n{doc['text']}\n"
            )

        context_block = "\n".join(context_parts)

        messages = [
            {"role": "system", "content": self.SYSTEM_PROMPT},
        ]

        # Include conversation history for multi-turn support
        for msg in self.conversation_history[-6:]:  # Last 3 exchanges
            messages.append(msg)

        user_message = f"""Based on the following retrieved context from our company documents, please answer the user's question.

=== RETRIEVED CONTEXT ===
{context_block}
=== END OF CONTEXT ===

User's Question: {query}

Please provide a comprehensive answer based on the above context."""

        messages.append({"role": "user", "content": user_message})
        return messages

    def query(self, user_query: str, top_k: int = TOP_K, verbose: bool = True) -> str:
        """Process a user query through the RAG pipeline."""
        if self.vector_db.size == 0:
            return "⚠️ The knowledge base is empty. Please ingest some documents first."

        # Step 1: Retrieve relevant documents
        if verbose:
            print(f"\n🔍 Searching for relevant documents...")
        retrieved_docs = self.retrieve(user_query, top_k=top_k)

        if not retrieved_docs:
            return "No relevant documents found for your query."

        if verbose:
            print(f"📄 Retrieved {len(retrieved_docs)} relevant chunks:")
            for i, doc in enumerate(retrieved_docs, 1):
                source = doc["metadata"].get("filename", "Unknown")
                score = doc.get("similarity_score", 0)
                preview = doc["text"][:80].replace("\n", " ")
                print(f"  {i}. [{source}] (score: {score:.3f}) {preview}...")

        # Step 2: Build prompt with context
        messages = self.build_prompt(user_query, retrieved_docs)

        # Step 3: Generate response
        if verbose:
            print(f"\n🤖 Generating response...")

        response = client.chat.completions.create(
            model=CHAT_MODEL,
            messages=messages,
            temperature=0.3,
            max_tokens=1500,
        )

        answer = response.choices[0].message.content

        # Update conversation history
        self.conversation_history.append({"role": "user", "content": user_query})
        self.conversation_history.append({"role": "assistant", "content": answer})

        return answer

    def clear_history(self):
        """Clear conversation history."""
        self.conversation_history = []
        print("🗑️ Conversation history cleared.")

    def get_stats(self) -> dict:
        """Get system statistics."""
        return {
            "total_chunks": self.vector_db.size,
            "conversation_turns": len(self.conversation_history) // 2,
            "vector_db_path": self.vector_db.db_path,
            "embedding_model": EMBEDDING_MODEL,
            "chat_model": CHAT_MODEL,
        }


