# --- Interactive Chat ---
def run_interactive_chat(rag: RAGSystem):
    """Run an interactive chat session."""
    print("\n" + "=" * 60)
    print("🤖 Acme Corp Knowledge Base Chatbot")
    print("=" * 60)
    print("Commands:")
    print("  /quit     - Exit the chatbot")
    print("  /clear    - Clear conversation history")
    print("  /stats    - Show system statistics")
    print("  /ingest   - Re-ingest documents")
    print("  /add      - Add a text document manually")
    print("=" * 60)

    while True:
        try:
            user_input = input("\n👤 You: ").strip()
        except (KeyboardInterrupt, EOFError):
            print("\n\n👋 Goodbye!")
            break

        if not user_input:
            continue

        if user_input.lower() == "/quit":
            print("👋 Goodbye!")
            break
        elif user_input.lower() == "/clear":
            rag.clear_history()
            continue
        elif user_input.lower() == "/stats":
            stats = rag.get_stats()
            print("\n📊 System Statistics:")
            for key, value in stats.items():
                print(f"  {key}: {value}")
            continue
        elif user_input.lower() == "/ingest":
            rag.ingest_documents()
            continue
        elif user_input.lower() == "/add":
            print("Enter document text (type 'END' on a new line to finish):")
            lines = []
            while True:
                line = input()
                if line.strip() == "END":
                    break
                lines.append(line)
            text = "\n".join(lines)
            name = input("Source name: ").strip() or "manual_input"
            rag.ingest_text(text, name)
            continue

        # Process the query
        answer = rag.query(user_input)
        print(f"\n🤖 Assistant: {answer}")


# --- Main ---
def main():
    """Main entry point."""
    import argparse

    parser = argparse.ArgumentParser(description="RAG Knowledge Base Chatbot")
    parser.add_argument(
        "--setup", action="store_true", help="Create sample documents and ingest them"
    )
    parser.add_argument(
        "--ingest", action="store_true", help="Ingest documents from the documents directory"
    )
    parser.add_argument(
        "--query", type=str, help="Run a single query instead of interactive mode"
    )
    parser.add_argument(
        "--docs-dir", type=str, default=DOCUMENTS_DIR, help="Documents directory path"
    )

    args = parser.parse_args()

    # Initialize the RAG system
    rag = RAGSystem()

    if args.setup:
        create_sample_documents()
        rag.ingest_documents(args.docs_dir)
        print("\n✅ Setup complete! Run without --setup to start chatting.")
        return

    if args.ingest:
        rag.ingest_documents(args.docs_dir)
        return

    if args.query:
        answer = rag.query(args.query)
        print(f"\n🤖 Answer: {answer}")
        return

    # Interactive mode
    if rag.vector_db.size == 0:
        print("⚠️  Vector store is empty!")
        print("Would you like to create sample documents and ingest them? (y/n)")
        try:
            choice = input("> ").strip().lower()
        except (KeyboardInterrupt, EOFError):
            return
        if choice == "y":
            create_sample_documents()
            rag.ingest_documents()
        else:
            print(f"Please add documents to '{DOCUMENTS_DIR}/' and run with --ingest flag.")
            return

    run_interactive_chat(rag)


if __name__ == "__main__":
    main()